\documentclass[tikz,border=10pt]{standalone}

% --- Required Packages ---
\usepackage{fontspec}
\usepackage{tikz}
\usetikzlibrary{positioning, arrows.meta}
\usepackage{xcolor}
\usepackage{bm}

% --- Font Setting ---
\setmainfont{Latin Modern Roman}

% --- K-5 Color Palette ---
\definecolor{K5_Red}{HTML}{ff2500}
\definecolor{K5_Indigo}{HTML}{2b0c81}
\definecolor{K5_White}{HTML}{ffffff}

\begin{document}
    \begin{tikzpicture}[
        font=\sffamily,
        node distance=1cm,
        % Styles
        button/.style={
            circle, 
            minimum size=2.5cm, 
            fill=K5_Red, 
            text=K5_White, 
            font=\fontsize{80}{88}\selectfont\bfseries, 
            inner sep=0pt
        },
        label_text/.style={
            text=K5_Indigo, 
            font=\fontsize{50}{58}\selectfont\bfseries, 
            anchor=east
        },
        value_text/.style={
            text=K5_Indigo, 
            font=\fontsize{50}{58}\selectfont\bfseries, 
            anchor=west
        }
    ]

        % Central Button

ode[button] (btn) {-};

        % Left Label

ode[label_text, left=1cm of btn] {Negative Integer};

        % Right Value

ode[value_text, right=1cm of btn] {-1};

    \end{tikzpicture}
\end{document}

